module RefModule(  
    input clock,  
    input reset,  
    input [7:0] signal_in,  
    input [7:0] threshold,  
    output reg detected  
);  

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clock or posedge reset or posedge dbg_halt) begin  
    if (reset) begin  
        detected <= 0;  
    end else begin  
        if (signal_in > threshold)  
            detected <= 1;  
        else  
            detected <= 0;  
    end  
end  
endmodule
